app.get('/files/:name', (req, res) => {
  const resolved = path.resolve(uploadDir, req.params.name);
  if (!resolved.startsWith(path.resolve(uploadDir))) {
    return res.status(400).json({ error: 'Invalid path' });
  }
  res.sendFile(resolved);
});

